import React, { useState } from 'react';
import { Play, Check, X, Loader2 } from 'lucide-react';

const Testing: React.FC = () => {
  const [running, setRunning] = useState<number | null>(null);

  const tests = [
    { id: 1, name: "Email Delivery (SMTP)", description: "Sends a test email to admin contact." },
    { id: 2, name: "SharePoint Upload", description: "Uploads a 1KB dummy file to configured library." },
    { id: 3, name: "Google Drive Permissions", description: "Verifies service account write access." },
    { id: 4, name: "Report Engine Render", description: "Generates a sample PDF using Jasper Engine." },
  ];

  const handleRun = (id: number) => {
    setRunning(id);
    setTimeout(() => setRunning(null), 2000); // Simulate running
  };

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-gray-900">Integration Test Suites</h1>
      <p className="text-gray-500">Run manual verifications of external system integrations.</p>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 divide-y divide-gray-100">
        {tests.map(test => (
          <div key={test.id} className="p-6 flex items-center justify-between hover:bg-gray-50">
             <div>
               <h3 className="font-semibold text-gray-900">{test.name}</h3>
               <p className="text-sm text-gray-500 mt-1">{test.description}</p>
             </div>
             <button 
               onClick={() => handleRun(test.id)}
               disabled={running === test.id}
               className={`flex items-center px-4 py-2 rounded-lg font-medium transition-colors ${
                 running === test.id 
                 ? 'bg-gray-100 text-gray-400' 
                 : 'bg-blue-50 text-blue-600 hover:bg-blue-100'
               }`}
             >
               {running === test.id ? (
                 <>
                   <Loader2 size={18} className="mr-2 animate-spin" /> Running...
                 </>
               ) : (
                 <>
                   <Play size={18} className="mr-2" /> Run Test
                 </>
               )}
             </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Testing;

